arguments.argument:
if global.gamePaused=false
{
  if life>0
  {
    path_speed=moveSpeed
    image_angle=direction
  }
  else if life<=0
  {
    tEfCir=instance_create(x,y,oEfCircleBlast)
    tEfCir.image_alpha=0.75; tEfCir.myRad=4; tEfCir.radScl=3; tEfCir.fadeSpeed=0.08
    instance_destroy()
  }
  enemyStepEvent()
}
else {path_speed=0}
